```typescript
let callCount = 0;
vi.mocked(embedText).mockImplementation(async () => {
  callCount++;
  if (callCount === 1) return new Float32Array([1, 0, 0]); // query
  return new Float32Array([0.9, 0.1, 0]); // items
});
